-- Phase 1 (requisición workflow): add the requisición content columns parsed
-- from the .docx into dim_requisitions. Idempotent — safe to re-run.

IF COL_LENGTH('dbo.dim_requisitions','puesto') IS NULL                  ALTER TABLE dbo.dim_requisitions ADD puesto NVARCHAR(300) NULL;
IF COL_LENGTH('dbo.dim_requisitions','direccion') IS NULL               ALTER TABLE dbo.dim_requisitions ADD direccion NVARCHAR(200) NULL;
IF COL_LENGTH('dbo.dim_requisitions','region_area') IS NULL             ALTER TABLE dbo.dim_requisitions ADD region_area NVARCHAR(200) NULL;
