IF COL_LENGTH('dbo.dim_requisitions','retos') IS NULL                   ALTER TABLE dbo.dim_requisitions ADD retos NVARCHAR(MAX) NULL;
IF COL_LENGTH('dbo.dim_requisitions','responsabilidades') IS NULL       ALTER TABLE dbo.dim_requisitions ADD responsabilidades NVARCHAR(MAX) NULL;
