IF COL_LENGTH('dbo.dim_requisitions','convenio_requerido') IS NULL      ALTER TABLE dbo.dim_requisitions ADD convenio_requerido BIT NULL;
IF COL_LENGTH('dbo.dim_requisitions','needs_review') IS NULL            ALTER TABLE dbo.dim_requisitions ADD needs_review BIT NULL;
